const parseRSS = (xml) => {
  const items = [];
  const itemRe = /<item[\s\S]*?<\/item>/gi;
  const titleRe = /<title><!\[CDATA\[([\s\S]*?)\]\]><\/title>|<title>([^<]*)<\/title>/;
  const descRe = /<description><!\[CDATA\[([\s\S]*?)\]\]><\/description>|<description>([^<]*)<\/description>/;
  const linkRe = /<link>([^<]*)<\/link>/;
  const dateRe = /<pubDate>([^<]*)<\/pubDate>/;
  let m;
  while ((m = itemRe.exec(xml)) !== null) {
    const chunk = m[0];
    const t = titleRe.exec(chunk); const d = descRe.exec(chunk);
    const l = linkRe.exec(chunk); const dt = dateRe.exec(chunk);
    items.push({
      title: (t && (t[1]||t[2]) || '').trim(),
      description: (d && (d[1]||d[2]) || '').replace(/<[^>]+>/g,'').trim().slice(0,300),
      link: l ? l[1].trim() : '',
      date: dt ? dt[1].trim() : ''
    });
  }
  return items;
};

const GEO_TERMS = /geo|aeo|answer engine|generative engine|ai search|llm seo|chatgpt traffic|perplexity|ai overview|sgе|search generative|cited by ai|llm referral|answer box|featured snippet|zero.click|voice search|conversational search/i;

const sources = [
  { name: 'SearchEngineLand', body: $('Fetch SEL').first().json.data || $('Fetch SEL').first().json.body || '' },
  { name: 'SEJ', body: $('Fetch SEJ').first().json.data || $('Fetch SEJ').first().json.body || '' },
  { name: 'Semrush', body: $('Fetch Semrush').first().json.data || $('Fetch Semrush').first().json.body || '' }
];

const allItems = [];
for (const src of sources) {
  const xml = typeof src.body === 'string' ? src.body : JSON.stringify(src.body);
  const items = parseRSS(xml);
  for (const item of items) {
    const text = item.title + ' ' + item.description;
    if (GEO_TERMS.test(text)) {
      allItems.push({ source: src.name, ...item });
    }
  }
}

const summary = allItems.slice(0, 8).map(i => `[${i.source}] ${i.title}\n${i.description}`).join('\n\n');
const count = allItems.length;

return [{ json: { items: allItems.slice(0, 8), summary, count } }];

