const groqResp = $input.first().json;
const raw = groqResp.choices[0].message.content;
let parsed = {};
try { const m = raw.match(/\{[\s\S]*\}/); parsed = m ? JSON.parse(m[0]) : {}; } catch(e) { parsed = { insights: [], summary: raw }; }

const output = {
  date: new Date().toISOString().slice(0,10),
  insights: parsed.insights || [],
  summary: parsed.summary || '',
  article_count: $('Parse & Filter').first().json.count
};
return [{ json: output }];

const d = $('Build Insights').first().json;
const insights = d.insights || [];

const lines = insights.map((i, idx) => {
  const prio = i.priority === 'high' ? '🔴' : '🟡';
  const sites = (i.applies_to || ['all']).join(', ');
  return `${prio} <b>${i.title}</b>\n   Action: ${i.action}\n   Sites: ${sites}`;
});

const text = '<b>GEO/AEO daglig intelligens</b>\n' +
  (d.article_count > 0 ? `${d.article_count} relevanta artiklar hittade\n` : 'Inga nya artiklar – generella insikter\n') +
  '\n' + (lines.length ? lines.join('\n\n') : d.summary);

return [{ json: { text } }];

